import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, expect, it } from "vitest";
const SRC_ROOT = join(__dirname, "..", "..", "src");
/**
 * `runOpenExperiments` is poller-owning (like `runStartDataset` /
 * `runOpenTracePlan`): it stays alive holding the session and streams JSON
 * lines on stdout. Stdout MUST therefore be a parseable JSONL stream — one
 * JSON line per event through the single approved channel (`emitJson` in
 * output.ts) — and the command MUST NOT use `console.log` (human-readable
 * status goes to stderr via `console.error`).
 *
 * The shared call-path modules (agentSessionChannel, sessionReady, config,
 * etc.) are already covered by startDataset.stdoutContract.test.ts; this file
 * guards the openExperiments command itself.
 */
const STDOUT_WRITE_RE = /process\.stdout\.write/g;
const CONSOLE_LOG_RE = /\bconsole\.log\b/g;
function readSrc(relPath) {
    return readFileSync(join(SRC_ROOT, relPath), "utf-8");
}
describe("openExperiments stdout contract", () => {
    it("openExperiments.ts: no direct stdout writes (uses shared emitJson)", () => {
        const src = readSrc("commands/openExperiments.ts");
        expect(src.match(STDOUT_WRITE_RE) ?? [], "openExperiments.ts must not call process.stdout.write directly — use " +
            "the shared emitJson() from output.ts so stdout stays a parseable " +
            "JSONL stream.").toEqual([]);
        expect(src.match(CONSOLE_LOG_RE) ?? [], "openExperiments.ts must not use console.log — use console.error for " +
            "human-readable status messages so stdout stays a parseable stream.").toEqual([]);
    });
});
